// 读取当前文档所有段落文本
var doc = Application.ActiveDocument;
if (!doc) {
  return { error: "未找到活动文档" };
}

var paragraphs = doc.Paragraphs;
var textList = [];
for (var i = 0; i < paragraphs.Count; i++) {
  var para = paragraphs.Item(i);
  var text = para.Range.Text;
  if (text && text.trim()) {
    textList.push({ index: i + 1, text: text.replace(/[\r\n]+$/g, '') });
  }
}

return {
  totalParagraphs: paragraphs.Count,
  content: textList.slice(0, 100) // 限制前100段以防过大
};

// 读取当前文档所有段落文本（兼容写法）
var doc = Application.ActiveDocument;
if (!doc) {
  return { error: "未找到活动文档" };
}

try {
  var text = doc.Content.Text;
  var paragraphs = text.split(/\r?\n/);
  var result = [];
  for (var i = 0; i < paragraphs.length; i++) {
    var line = paragraphs[i].trim();
    if (line) {
      result.push({ index: i + 1, text: line });
    }
  }
  return { totalParagraphs: result.length, content: result.slice(0, 100) };
} catch (e) {
  return { error: e.message };
}
